/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(VendOpenTrans, MarkTrans), FormControlEventType::Clicked)]
public static void MarkTrans_OnClicked(FormControl sender, FormControlEventArgs e)
{
    if (ETGACFParameters::find().EnableUATSmallPoints)
    {
        FormCheckBoxControl checkBoxControl = sender as FormCheckBoxControl;

        if (checkBoxControl)
        {
            FormRun formRun = checkBoxControl.formRun();
            formRun.updateMarkedTotals();

            container controlNames = ["showTransactionAmountCur", "ShowRemainAmountTransCur", "showCashDiscTotalTransCur"];
            int controlCount = conLen(controlNames);

            for (int i = 1; i <= controlCount; i++)
            {
                str controlName = conPeek(controlNames, i);
                FormControl ctrl = formRun.design().controlName(controlName);

                if (ctrl)
                {
                    FormControl boundControl = formRun.control(ctrl.id());
                    if (boundControl)
                    {
                        boundControl.update();
                    }
                }
            }
        }
    }
}
